## Zone Constraint Tests (CRITICAL)

```rust
#[tokio::test]
async fn test_batch_invoke_zone_validation_rejects_violation() {
    // Zone boundary violations are rejected before execution
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation {
                id: "op1".into(),
                tool: "fcp.owner-only.tool".into(),  // z:owner zone
                input: json!({}),
                depends_on: vec![],
            },
        ],
        options: BatchOptions::default(),
    };

    // Agent in z:work cannot access z:owner
    let result = harness.batch_invoke_as_zone("z:work", batch).await;
    assert!(matches!(result, Err(FcpError::ZoneBoundaryViolation { operation_id, .. }) if operation_id == "op1"));
}

#[tokio::test]
async fn test_batch_invoke_zone_validation_allows_same_zone() {
    // Operations in agent's zone succeed
    let harness = TestHarness::new().await;
    harness.register_connector_in_zone("test.echo", "z:work").await;

    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.echo".into(), input: json!({}), depends_on: vec![] },
        ],
        options: BatchOptions::default(),
    };

    let result = harness.batch_invoke_as_zone("z:work", batch).await;
    assert!(result.is_ok());
}

#[tokio::test]
async fn test_batch_invoke_cross_zone_uses_separate_tokens() {
    // Cross-zone batch uses different capability tokens per zone
    let harness = TestHarness::new().await;
    harness.register_connector_in_zone("fcp.work.tool", "z:work").await;
    harness.register_connector_in_zone("fcp.project.tool", "z:project:myproj").await;

    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "fcp.work.tool".into(), input: json!({}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "fcp.project.tool".into(), input: json!({}), depends_on: vec![] },
        ],
        options: BatchOptions::default(),
    };

    let (response, audit) = harness.batch_invoke_with_audit("z:work", batch).await.unwrap();

    // Verify different capability tokens were used
    let op1_token = audit.get_token_for_operation("op1");
    let op2_token = audit.get_token_for_operation("op2");
    assert_ne!(op1_token.zone, op2_token.zone);
}

#[tokio::test]
async fn test_batch_invoke_zone_violation_audit_trail() {
    // Zone violations produce proper audit entries
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "fcp.owner.tool".into(), input: json!({}), depends_on: vec![] },
        ],
        options: BatchOptions::default(),
    };

    let _ = harness.batch_invoke_as_zone("z:public", batch).await;

    // Verify audit entry was created for denial
    let audit = harness.get_last_audit_entry().await;
    assert_eq!(audit.decision, "deny");
    assert_eq!(audit.reason_code, "zone_boundary_violation");
    assert!(audit.evidence.contains(&"op1"));
}
